import json, sys

def main():
    try:
        ev = json.load(sys.stdin)
    except Exception:
        return 0  # never break Claude Code on bad input

    tool  = ev.get("tool_name", "")
    inp   = ev.get("tool_input") or {}

    if tool != "Bash":
        return 0

    cmd = inp.get("command", "")

    # Block 'pnpm test' (interactive) — suggest 'pnpm test:ci' instead
    # Allow 'pnpm test:ci' (non-interactive, what we want)
    if cmd.startswith("pnpm test") and "test:ci" not in cmd:
        msg = "pnpm test runs interactively and will hang. Use 'pnpm test:ci' for non-interactive testing."
        print(msg, file=sys.stderr)
        return 2

    return 0

if __name__ == "__main__":
    sys.exit(main())

import json, sys, subprocess

def main():
    try:
        ev = json.load(sys.stdin)
    except Exception:
        return 0

    tool = ev.get("tool_name", "")
    inp = ev.get("tool_input") or {}

    if tool != "Edit":
        return 0

    file_path = inp.get("file_path", "")
    if not file_path.endswith(".py"):
        return 0

    try:
        subprocess.run(
            ["ruff", "format", file_path],
            capture_output=True,
            timeout=10
        )
    except Exception:
        pass

    return 0

if __name__ == "__main__":
    sys.exit(main())

import json, sys, re

def main():
    try:
        ev = json.load(sys.stdin)
    except Exception:
        return 0

    tool = ev.get("tool_name", "")
    inp = ev.get("tool_input") or {}

    if tool != "Edit":
        return 0

    file_path = inp.get("file_path", "")
    new_string = inp.get("new_string", "")

    # Skip .env files, examples, and documentation
    if any(skip in file_path for skip in [".env", "example", ".md", ".txt"]):
        return 0

    # Patterns that strongly indicate hardcoded secrets
    secret_patterns = [
        r'sk-proj-[a-zA-Z0-9_\-]+',  # OpenAI API keys
        r'sk-live-[a-zA-Z0-9_\-]+',  # Stripe live key
        r'sk-test-[a-zA-Z0-9_\-]+',  # Stripe test key
        r'Bearer\s+[a-zA-Z0-9_\-\.]+',  # Bearer tokens
        r'ghp_[a-zA-Z0-9_]+',  # GitHub personal access tokens
        r'glpat-[a-zA-Z0-9_\-]+',  # GitLab tokens
    ]

    for pattern in secret_patterns:
        if re.search(pattern, new_string):
            msg = "BLOCKING: Attempted to write a hardcoded secret (API key, token, or password) to source.\nSecrets must come from environment variables (process.env). See CLAUDE.md: 'Secrets come from the environment.'"
            print(msg, file=sys.stderr)
            return 2

    return 0

if __name__ == "__main__":
    sys.exit(main())

