import json, sys

def main():
    try:
        ev = json.load(sys.stdin)
    except Exception:
        return 0

    tool = ev.get("tool_name", "")
    inp = ev.get("tool_input") or {}

    if tool != "Bash":
        return 0

    cmd = inp.get("command", "")

    # Check for git add or git commit with .env
    if ("git add" in cmd or "git commit" in cmd) and ".env" in cmd:
        # Allow .env.example, .env.template, .env.sample and other safe variants
        if ".env.example" not in cmd and ".env.template" not in cmd and ".env.sample" not in cmd:
            msg = "BLOCKING: Do not commit real .env files with secrets. Only .env.example and template files should be committed. Check your staging area with 'git diff --cached'; use 'git add -p' to stage specific changes."
            print(msg, file=sys.stderr)
            return 2

    return 0

if __name__ == "__main__":
    sys.exit(main())

